mapper.select:
SELECT fl.factory_line_id, fl.factory_line_code, fl.factory_line_name, COUNT(DISTINCT o.order_id) AS total_order_count, SUM(CASE WHEN o.order_status = 'COMPLETED' THEN 1 ELSE 0 END) AS completed_count, COALESCE(ROUND( SUM(CASE WHEN o.order_status = 'COMPLETED' THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(DISTINCT o.order_id), 0), 1 ), 0.0) AS achievement_rate, COALESCE(ROUND( COUNT(DISTINCT CASE WHEN eq.equipment_status = 'OPERATING' THEN eq.equipment_id END) * 100.0 / NULLIF(COUNT(DISTINCT eq.equipment_id), 0), 1 ), 0.0) AS operation_rate FROM factory_line fl JOIN equipment_process ep ON fl.factory_line_id = ep.factory_line_id AND COALESCE(ep.is_deleted, false) = false JOIN equipment eq ON ep.equipment_process_id = eq.equipment_process_id AND COALESCE(eq.is_deleted, false) = false JOIN worker_deployment wd ON eq.equipment_id = wd.equipment_id AND wd.employee_id IN
#{id}
AND (wd.end_date IS NULL OR wd.end_date >= CURDATE()) LEFT JOIN matching_record mr ON wd.employee_id = mr.employee_id AND COALESCE(DATE(mr.work_start_at), DATE(mr.created_at)) BETWEEN wd.start_date AND COALESCE(wd.end_date, CURDATE()) AND mr.matching_status != 'REJECT' LEFT JOIN orders o ON mr.order_id = o.order_id WHERE COALESCE(fl.is_deleted, false) = false GROUP BY fl.factory_line_id, fl.factory_line_code, fl.factory_line_name

AND e.employee_id IN
#{id}
GROUP BY fl.factory_line_id, e.employee_id, e.employee_name, e.employee_tier ORDER BY e.employee_name
